#!/bin/bash

PROJECT_ID="pushtes-f91bf"
DEVICE_TOKEN="doEyyxUBQEmZBxeZkGBHld:APA91bH5CH_3MmbW1JIg30cvkbGt1rBZj8MniOnaUwBPCP7OZe9deKfLzKQE769kyIv-XVdM-L-KErMOhw74DbFLlNdHZY4g-Subl9ety-12r8m9Ark_Osg"
KEY_FILE="service-account-key.json"

# Получение токена
ACCESS_TOKEN=$(gcloud auth activate-service-account --key-file="$KEY_FILE" 2>&1 > /dev/null && gcloud auth print-access-token)
echo $ACCESS_TOKEN
#ACCESS_TOKEN=""

# Отправка уведомления
curl -X POST \
  https://fcm.googleapis.com/v1/projects/$PROJECT_ID/messages:send \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $ACCESS_TOKEN" \
  -d "{
    \"message\": {
      \"token\": \"$DEVICE_TOKEN\",
      \"notification\": {
        \"title\": \"Тест\",
        \"body\": \"Работает!\"
      }
    }
  }"
